#include "framebuffer.h"
// 5x7 font. Each glyph = 7 rows, low 5 bits, bit4 = leftmost column.
// Covers the characters the starter widgets need; extend as new widgets need more.

namespace {
struct Glyph { char c; uint8_t rows[7]; };
const Glyph FONT[] = {
    {' ', {0x00,0x00,0x00,0x00,0x00,0x00,0x00}},
    {'0', {0x0E,0x11,0x13,0x15,0x19,0x11,0x0E}},
    {'1', {0x04,0x0C,0x04,0x04,0x04,0x04,0x0E}},
    {'2', {0x0E,0x11,0x01,0x02,0x04,0x08,0x1F}},
    {'3', {0x1F,0x02,0x04,0x02,0x01,0x11,0x0E}},
    {'4', {0x02,0x06,0x0A,0x12,0x1F,0x02,0x02}},
    {'5', {0x1F,0x10,0x1E,0x01,0x01,0x11,0x0E}},
    {'6', {0x06,0x08,0x10,0x1E,0x11,0x11,0x0E}},
    {'7', {0x1F,0x01,0x02,0x04,0x08,0x08,0x08}},
    {'8', {0x0E,0x11,0x11,0x0E,0x11,0x11,0x0E}},
    {'9', {0x0E,0x11,0x11,0x0F,0x01,0x02,0x0C}},
    {'-', {0x00,0x00,0x00,0x1F,0x00,0x00,0x00}},
    {'R', {0x1E,0x11,0x11,0x1E,0x14,0x12,0x11}},
    {'N', {0x11,0x19,0x15,0x13,0x11,0x11,0x11}},
    {'D', {0x1E,0x11,0x11,0x11,0x11,0x11,0x1E}},
    {'%', {0x18,0x19,0x02,0x04,0x08,0x13,0x03}},
};
}

const uint8_t *font_glyph(char c) {
    for (const auto &g : FONT) if (g.c == c) return g.rows;
    return nullptr;   // unknown char -> caller skips
}
